Chapter IV Development of the 2024 QC Minimodel Mathematica® Inc. 47 ii. Specification For each unit, we aggregate the countable income of all members in the household. Gross income is the sum of all earned and unearned income. When appropriate, we exclude child support expenses from the gross income. (There are separate values that indicate expenses to be subtracted before the gross income test [EXFSCSDED] and expenses to be subtracted before the net income test [FSCSDED].) We loop over all individuals in the household:40 40All individuals in the household include all individuals in the SNAP unit under review, plus individuals outside the unit who contribute income to the unit. do iunit = 1, ctprhh

do ip = 1, ctprhh

if (l_dpcost%iper(ip) > 0) depexp(iunit) = depexp(iunit) + l_dpcost%iper(ip)

!-------- WELFARE Support (Note: missing income values are coded as < 0)

if (l_tanf%iper(ip) > 0) fstanf(iunit) = fstanf(iunit) + l_tanf%iper(ip)

if (l_ssi %iper(ip) > 0) then

fsssi (iunit) = fsssi (iunit) + l_ssi %iper(ip)

nssi = nssi + 1

endif

if (l_ga %iper(ip) > 0) fsga (iunit) = fsga (iunit) + l_ga %iper(ip)

!---- Earned income

if (l_wages %iper(ip) >0) fsearn(iunit) = fsearn(iunit) + l_wages %iper(ip)

if (l_othern%iper(ip) >0) fsearn(iunit) = fsearn(iunit) + l_othern%iper(ip)

if (l_slfemp%iper(ip) >0) fsearn(iunit) = fsearn(iunit) + l_slfemp%iper(ip)

if (l_rentminc%iper(ip) >0) fsearn(iunit) = fsearn(iunit) + l_rentminc%iper(ip)

!---- Other unearned income

if (l_othgov%iper(ip) > 0) fsgrinc(iunit) = fsgrinc(iunit) + l_othgov%iper(ip)

if (l_socsec%iper(ip) > 0) fsgrinc(iunit) = fsgrinc(iunit) + l_socsec%iper(ip)

if (l_unemp %iper(ip) > 0) fsgrinc(iunit) = fsgrinc(iunit) + l_unemp %iper(ip)

if (l_vet %iper(ip) > 0) fsgrinc(iunit) = fsgrinc(iunit) + l_vet %iper(ip)

if (l_wcomp %iper(ip) > 0) fsgrinc(iunit) = fsgrinc(iunit) + l_wcomp %iper(ip)

if (l_edloan%iper(ip) > 0) fsgrinc(iunit) = fsgrinc(iunit) + l_edloan%iper(ip)

if (l_csuprt%iper(ip) > 0) fsgrinc(iunit) = fsgrinc(iunit) + l_csuprt%iper(ip)

if (l_deem %iper(ip) > 0) fsgrinc(iunit) = fsgrinc(iunit) + l_deem %iper(ip)

if (l_cont %iper(ip) > 0) fsgrinc(iunit) = fsgrinc(iunit) + l_cont %iper(ip)

if (l_othun %iper(ip) > 0) fsgrinc(iunit) = fsgrinc(iunit) + l_othun %iper(ip)

if (l_diver %iper(ip) > 0) fsgrinc(iunit) = fsgrinc(iunit) + l_diver %iper(ip)

if (l_wgesup%iper(ip) > 0) fsgrinc(iunit) = fsgrinc(iunit) + l_wgesup%iper(ip)

if (l_energy%iper(ip) > 0) fsgrinc(iunit) = fsgrinc(iunit) + l_energy%iper(ip)

if (l_foster%iper(ip) > 0) fsgrinc(iunit) = fsgrinc(iunit) + l_foster%iper(ip)

if (l_alimny%iper(ip) > 0) fsgrinc(iunit) = fsgrinc(iunit) + l_alimny%iper(ip)

if (l_annuity%iper(ip) > 0) fsgrinc(iunit) = fsgrinc(iunit) + l_annuity%iper(ip)

if (l_govdiv%iper(ip) > 0) fsgrinc(iunit) = fsgrinc(iunit) + l_govdiv%iper(ip)

if (l_govinter%iper(ip) > 0) fsgrinc(iunit) = fsgrinc(iunit) + l_govinter%iper(ip)

if (l_govroy%iper(ip) > 0) fsgrinc(iunit) = fsgrinc(iunit) + l_govroy%iper(ip)

if (l_inter%iper(ip) > 0) fsgrinc(iunit) = fsgrinc(iunit) + l_inter%iper(ip)

if (l_oldage%iper(ip) > 0) fsgrinc(iunit) = fsgrinc(iunit) + l_oldage%iper(ip)

if (l_pension%iper(ip) > 0) fsgrinc(iunit) = fsgrinc(iunit) + l_pension%iper(ip)

if (l_rentinc%iper(ip) > 0) fsgrinc(iunit) = fsgrinc(iunit) + l_rentinc%iper(ip)

if (l_strike%iper(ip) > 0) fsgrinc(iunit) = fsgrinc(iunit) + l_strike%iper(ip)

if (l_surv%iper(ip) > 0) fsgrinc(iunit) = fsgrinc(iunit) + l_surv%iper(ip)

if (l_trust%iper(ip) > 0) fsgrinc(iunit) = fsgrinc(iunit) + l_trust%iper(ip)

if (l_unk%iper(ip) > 0) fsgrinc(iunit) = fsgrinc(iunit) + l_unk%iper(ip)
